// ─── Dark side template parts ───
// Black outer, gradient inner, black oval stroke, black symbols
const DARK_OUTER_RECT =
  '<path fill="#000" stroke="#333" stroke-width="2" d="M201 1H41C18.909 1 1 18.909 1 41v280c0 22.091 17.909 40 40 40h160c22.091 0 40-17.909 40-40V41c0-22.091-17.909-40-40-40Z"/>';

const DARK_INNER_RECT =
  '<path fill="url(#grad)" d="M201 21H41c-11.046 0-20 8.954-20 20v280c0 11.046 8.954 20 20 20h160c11.046 0 20-8.954 20-20V41c0-11.046-8.954-20-20-20"/>';

const DARK_OVAL =
  '<path fill="url(#grad)" stroke="#000" stroke-width="5" d="M181 83.5c20.711 0 37.5 16.789 37.5 37.5 0 86.985-70.515 157.5-157.5 157.5-20.71 0-37.5-16.789-37.5-37.5 0-86.985 70.515-157.5 157.5-157.5Z"/>';

// Recolor the wild card's BLACK inner background to the chosen color. The
// 4-color diamond and the white +N / wild text stay untouched, so the symbol
// remains legible (UNO Mobile does it this way too). `stroke="black"` on the
// outer card border is intentionally untouched.
function tintWildSvg(svg: string, hex: string): string {
  return svg.replaceAll('fill="black"', `fill="${hex}"`);
}

// ─── Build a complete card SVG string ───
export function buildCardSvg(
  color: string,
  value: string,
  side: "light" | "dark" = "light",
  gradient?: { start: string; end: string } | null,
  chosenColorHex?: string,
): string {
  // Wild cards have their own complete SVG (same for both sides). When a
  // chosen color is provided (only for the top of the discard pile), tint
  // the whole 4-color diamond + corner badges to that single color.
  if (
    value === "wild" ||
    value === "wild_draw_two" ||
    value === "wild_draw_color"
  ) {
    const baseSvg =
      value === "wild"
        ? WILD_SVG
        : value === "wild_draw_two"
          ? WILD_DRAW_TWO_SVG
          : WILD_DRAW_COLOR_SVG;
    return chosenColorHex ? tintWildSvg(baseSvg, chosenColorHex) : baseSvg;
  }

  const valuePath = VALUE_PATHS[value] ?? "";

  if (side === "dark" && gradient) {
    // Dark side: black card, gradient fill, black symbols
    const darkValuePath = valuePath.replaceAll('fill="#fff"', 'fill="#000"');
    return `<svg xmlns="http://www.w3.org/2000/svg" width="242" height="362" fill="none">
  <defs>
    <linearGradient id="grad" x1="0" y1="0" x2="242" y2="362" gradientUnits="userSpaceOnUse">
      <stop offset="0%" stop-color="${gradient.start}"/>
      <stop offset="100%" stop-color="${gradient.end}"/>
    </linearGradient>
  </defs>
  ${DARK_OUTER_RECT}
  ${DARK_INNER_RECT}
  ${DARK_OVAL}
  ${darkValuePath}
</svg>`;
  }

  // Light side: white card, solid color, white symbols
  return `<svg xmlns="http://www.w3.org/2000/svg" width="242" height="362" fill="none">
  ${OUTER_RECT}
  ${INNER_RECT.replaceAll("COLOR", color)}
  ${OVAL.replaceAll("COLOR", color)}
  ${valuePath}
</svg>`;
}
